class RockyConfig(BaseModel):
    """
    Top-level Rocky configuration (v2 format).

    Uses named adapters and named pipelines: ```toml [adapter.databricks_prod] type = "databricks" ...

    [pipeline.raw_replication] type = "replication" ... ```
    """

